sql:
SELECT 
    (SELECT COUNT(*) FROM salary_caps WHERE current_spending > total_cap) AS teams_over_salary_cap,
    (SELECT COUNT(*) FROM teams) AS total_number_of_teams;

external_knowledge:
- "Shining stars in the league" refers to teams that stand out for their financial and performance metrics;
- "Collective wealth of their players surpasses $15 million" refers to the total annual salary of all players on the team being greater than $15,000,000;
- "Batting average that outshines the twilight with over 0.250" refers to a batting average greater than 0.250;
- "Home run record that breaks the sound barrier with more than 20 home runs" refers to a player having more than 20 home runs.

- "Top 10 highest-earning players" refers to the players with the highest average annual salaries across all teams;
- "Earning" is derived from the `annual_salary` column in the `contracts` table;
- "Teams" are identified by the `team_name` column in the `teams` table.

sql:
SELECT COUNT(player_id)
FROM players
WHERE status = 'active';

external_knowledge:
